Here are the public test cases for feature6_2_singleton_counter:
{
  "description": "An application-scoped resource exposes a shared integer counter via a sub-path that can be read (GET, returns the current value then post-increments) and set (PUT, body is the new integer value, response carries no content). Because the resource lives for the whole application lifetime, the counter persists across requests. Input is a sequence of requests: set to 10, read (returns 10), read again (returns 11), set to 32, read (returns 32). Output concatenates each request's status, routed URL, and body separated by a blank line; a successful set returns status 204 with an empty body.",
  "cases": [
    {
      "input": {
        "requests": [
          {
            "app": "main",
            "path": "jcdibean/singleton/alpha/counter",
            "query": {
              "x": "beta"
            },
            "method": "PUT",
            "body": "10"
          },
          {
            "app": "main",
            "path": "jcdibean/singleton/alpha/counter",
            "query": {
              "x": "beta"
            }
          },
          {
            "app": "main",
            "path": "jcdibean/singleton/alpha/counter",
            "query": {
              "x": "beta"
            }
          },
          {
            "app": "main",
            "path": "jcdibean/singleton/alpha/counter",
            "query": {
              "x": "beta"
            },
            "method": "PUT",
            "body": "32"
          },
          {
            "app": "main",
            "path": "jcdibean/singleton/alpha/counter",
            "query": {
              "x": "beta"
            }
          }
        ]
      },
      "expected_output": "status=204\nurl=http://localhost:9998/main/jcdibean/singleton/alpha/counter?x=beta\nbody=\n\nstatus=200\nurl=http://localhost:9998/main/jcdibean/singleton/alpha/counter?x=beta\nbody=10\n\nstatus=200\nurl=http://localhost:9998/main/jcdibean/singleton/alpha/counter?x=beta\nbody=11\n\nstatus=204\nurl=http://localhost:9998/main/jcdibean/singleton/alpha/counter?x=beta\nbody=\n\nstatus=200\nurl=http://localhost:9998/main/jcdibean/singleton/alpha/counter?x=beta\nbody=32"
    }
  ]
}

